SELECT CAST(year AS INT) AS year, CAST(month AS INT) AS month, reporting_airline, COUNT(*) AS total_delayed_flights, ROUND(AVG(carrierdelay), 2) AS avg_carrier_delay_min, ROUND(AVG(weatherdelay), 2) AS avg_weather_delay_min, ROUND(AVG(nasdelay), 2) AS avg_nas_delay_min, ROUND(AVG(securitydelay), 2) AS avg_security_delay_min, ROUND(AVG(lateaircraftdelay), 2) AS avg_late_aircraft_delay_min, ROUND(SUM(COALESCE(carrierdelay, 0)), 0) AS total_carrier_delay_min, ROUND(SUM(COALESCE(weatherdelay, 0)), 0) AS total_weather_delay_min, ROUND(SUM(COALESCE(nasdelay, 0)), 0) AS total_nas_delay_min, ROUND(SUM(COALESCE(securitydelay, 0)), 0) AS total_security_delay_min, ROUND(SUM(COALESCE(lateaircraftdelay, 0)), 0) AS total_late_aircraft_delay_min, SUM(CASE WHEN carrierdelay > 0 THEN 1 ELSE 0 END) AS flights_carrier_delay, SUM(CASE WHEN weatherdelay > 0 THEN 1 ELSE 0 END) AS flights_weather_delay, SUM(CASE WHEN nasdelay > 0 THEN 1 ELSE 0 END) AS flights_nas_delay, SUM(CASE WHEN securitydelay > 0 THEN 1 ELSE 0 END) AS flights_security_delay, SUM(CASE WHEN lateaircraftdelay > 0 THEN 1 ELSE 0 END) AS flights_late_aircraft_delay, ROUND(SUM(COALESCE(carrierdelay, 0)) + SUM(COALESCE(lateaircraftdelay, 0)), 0) AS total_controllable_delay_min, ROUND(SUM(COALESCE(weatherdelay, 0)) + SUM(COALESCE(nasdelay, 0)) + SUM(COALESCE(securitydelay, 0)), 0) AS total_uncontrollable_delay_min, ROUND(100.0 * (SUM(COALESCE(carrierdelay, 0)) + SUM(COALESCE(lateaircraftdelay, 0))) / NULLIF(SUM(COALESCE(carrierdelay, 0)) + SUM(COALESCE(weatherdelay, 0)) + SUM(COALESCE(nasdelay, 0)) + SUM(COALESCE(securitydelay, 0)) + SUM(COALESCE(lateaircraftdelay, 0)), 0), 2) AS controllable_delay_pct FROM silver_flights WHERE arrdelay > 15 AND cancelled = 0 AND diverted = 0 GROUP BY year, month, reporting_airline
